  assert.match(receipt, /map\(\|style\| style\.source_map_source_hash_count\)\s*\.sum\(\)/);
  assert.match(receipt, /map\(\|style\| style\.source_map_entry_style_source_count\)\s*\.sum\(\)/);
  assert.match(receipt, /map\(\|style\| style\.source_map_flattened_import_source_count\)\s*\.sum\(\)/);
