  assert.match(ecosystemGraph, /sourceMapEvidenceOnlyCount/);
  assert.match(ecosystemGraph, /sourceMapLinkCount/);
  assert.match(ecosystemGraph, /sourceMapHashCount/);
  assert.match(ecosystemGraph, /node\["source_map_source_count"\]/);
  assert.match(ecosystemGraph, /node\["source_map_source_hash_count"\]/);
  assert.match(ecosystemGraph, /node\["source_map_entry_style_source_count"\]/);
