  assert.match(ecosystemGraph, /"import_specifier": reference\.import_specifier\.as_deref\(\)/);
  assert.match(handoff, /"source_map_source_count"/);
  assert.match(handoff, /style\.source_map_source_count/);
  assert.match(handoff, /"source_map_source_hash_count"/);
  assert.match(handoff, /style\.source_map_source_hash_count/);
  assert.match(handoff, /"source_map_entry_style_source_count"/);
  assert.match(handoff, /style\.source_map_entry_style_source_count/);
  assert.match(handoff, /"source_map_flattened_import_source_count"/);
  assert.match(handoff, /style\.source_map_flattened_import_source_count/);
  assert.match(handoff, /"source_map_retained_import_source_count"/);
  assert.match(handoff, /style\.source_map_retained_import_source_count/);
  assert.match(handoff, /"source_map_segment_count"/);
  assert.match(handoff, /style\.source_map_segment_count/);
  assert.match(handoff, /"source_map_exact_segment_map_count"/);
  assert.match(handoff, /style\.source_map_exact_segment_mapping/);
  assert.match(handoff, /"source_map_evidence_only_count"/);
  assert.match(handoff, /style\.source_map_evidence_only/);
  assert.match(handoff, /"source_map_link_count"/);
  assert.match(handoff, /style\.source_map_linked/);
