  assert.match(sourceBuildCssFixture, /\.\.\/\.\.\/public\/icons\/card\.svg/);
  assert.match(sourceBuildCssFixture, /"public\/icons\/card\.svg"/);
  assert.match(sourceBuildCssFixture, /source_build_resolves_css_url_assets_from_retained_local_import_origins/);
  assert.match(sourceBuildCssFixture, /"\.\.\/tokens\/layered\.css"/);
