  assert.match(sourceBuildCssFixture, /source_map_exact_segment_mapping/);
  assert.match(sourceBuildCssFixture, /source_map_evidence_only/);
  assert.match(sourceBuildCssFixture, /css_source_map_retained_import_sources/);
  assert.match(sourceBuildCssFixture, /css_source_map_exact_segment_maps/);
  assert.match(sourceBuildCssFixture, /css_source_map_evidence_only_maps/);
  assert.match(sourceBuildCssFixture, /css_retained_import_asset_references/);
  assert.match(sourceBuildCssFixture, /"dx-style-css:styles\/app\.css"/);
  assert.match(sourceBuildCssFixture, /"public-asset:public\/icons\/card\.svg"/);

  assert.match(fixture, /@import url/);
  assert.match(fixture, /@import \\"..\/tokens\/theme\\"/);
  assert.match(fixture, /"tokens\/url-theme.css"/);
  assert.match(fixture, /"tokens\/print.css"/);
  assert.match(fixture, /@media print\{\.print-only\{color:black;\}\}/);
  assert.match(fixture, /source_map_source_count"\]\s*,\s*4/);
  assert.match(fixture, /source_map_source_hash_count"\]\s*,\s*4/);
  assert.match(fixture, /source_map_entry_style_source_count"\]\s*,\s*1/);
  assert.match(fixture, /source_map_flattened_import_source_count"\]\s*,\s*3/);
  assert.match(fixture, /source_map_linked"\]\s*,\s*true/);
  assert.match(fixture, /source_map_hash"\]\s*\.as_str\(\)/);
  assert.match(fixture, /source_map_hash\.len\(\), 16/);
  assert.match(fixture, /source_map\["x_dx_css_pipeline"\]\["source_hashes"\]/);
  assert.match(fixture, /source_map\["x_dx_css_pipeline"\]\["parity_status"\]/);
  assert.match(fixture, /source_map\["x_dx_css_pipeline"\]\["runtime_boundary"\]/);
  assert.match(fixture, /source_map\["x_dx_css_pipeline"\]\["requires_node_modules"\]/);
  assert.match(fixture, /source_map\["x_dx_css_pipeline"\]\["full_lightning_css_parity"\]/);
  assert.match(fixture, /source_map\["x_dx_css_pipeline"\]\["turbopack_public_architecture"\]/);
  assert.match(fixture, /source_hashes\.len\(\), 4/);
  assert.match(fixture, /entry\["role"\] == "entry-style"/);
  assert.match(fixture, /entry\["role"\] == "flattened-import"/);
  assert.match(fixture, /filter\(\|entry\| entry\["role"\] == "flattened-import"\)/);
  assert.match(fixture, /css_source_map_sources"\]\s*,\s*4/);
  assert.match(fixture, /css_source_map_source_hashes"\]\s*,\s*4/);
  assert.match(fixture, /css_source_map_entry_style_sources"\]\s*,\s*1/);
  assert.match(fixture, /css_source_map_flattened_import_sources"\]\s*,\s*3/);
  assert.match(fixture, /css_source_map_links"\]\s*,\s*1/);
  assert.match(fixture, /css_source_map_hashes"\]\s*,\s*1/);
  assert.match(fixture, /compiled_css\.contains\("\/\*# sourceMappingURL=app\.css\.map \*\/"\)/);
  assert.match(fixture, /compiled_css\.contains\("--dx-url-accent:rgb\(40 50 60\);"\)/);
  assert.match(fixture, /"retained_imports"/);
  assert.match(fixture, /"external-or-rooted"/);
  assert.match(fixture, /css_retained_imports"\]\s*,\s*1/);
